  "type": "module",
  "bin": {
    "trace": "./dist/cli.js"
  },
  "scripts": {
    "build": "tsc",
    "dev": "tsc --watch",
    "start": "node ./dist/cli.js",
    "test": "echo \"(tests to come)\" && exit 0"
  },
  "keywords": [
    "claude-code",
    "prd",
    "living-document",
    "hackathon",
    "opus-4.7"
  ],
  "author": "Shandar Junaid <hello@affordancedesign.in>",
